     5→// Shared settings cache and save logic for persistent state
     6→const settingsCache = { current: null, loaded: false, listeners: new Set() };
     7→
     8→function loadSettings() {
     9→  if (settingsCache.loaded) return Promise.resolve(settingsCache.current);
    10→
    11→  // Use Electron IPC if available, fallback to fetch for web
    12→  const apiCall = window.api?.settings?.load
    13→    ? window.api.settings.load()
    14→    : fetch('/api/settings').then(r => r.ok ? r.json() : {});
    15→
    16→  return apiCall
    17→    .then(data => { settingsCache.current = data; settingsCache.loaded = true; return data; })
    18→    .catch(() => { settingsCache.current = {}; settingsCache.loaded = true; return {}; });
    19→}
    20→
    21→let saveTimer = null;
    22→function saveSettings(allSettings) {
    23→  settingsCache.current = { ...settingsCache.current, ...allSettings };
    24→  clearTimeout(saveTimer);
    25→  saveTimer = setTimeout(() => {
    26→    // Use Electron IPC if available, fallback to fetch for web
    27→    const apiCall = window.api?.settings?.save
    28→      ? window.api.settings.save(settingsCache.current)
    29→      : fetch('/api/settings', {
    30→          method: 'POST',
    31→          headers: { 'Content-Type': 'application/json' },
    32→          body: JSON.stringify(settingsCache.current)
    33→        });
    34→
    35→    apiCall.catch(() => {});
    36→  }, 500);
    37→}
