    39→// Custom hook for API-backed persistent state
    40→function usePersistentState(key, initialValue) {
    41→  const [value, setValueRaw] = useState(initialValue);
    42→
    43→  useEffect(() => {
    44→    loadSettings().then(data => {
    45→      if (data[key] !== undefined) setValueRaw(data[key]);
    46→    });
    47→  }, [key]);
    48→
    49→  const setValue = useCallback((updater) => {
    50→    setValueRaw(prev => {
    51→      const next = updater instanceof Function ? updater(prev) : updater;
    52→      saveSettings({ [key]: next });
    53→      return next;
    54→    });
    55→  }, [key]);
    56→
    57→  return [value, setValue];
    58→}
