   447→  <script>
   448→    // Debug mode (set to false to hide debug panel)
   449→    const DEBUG = false;
   450→
   451→    function debug(...args) {
   452→      if (DEBUG) {
   453→        console.log('[SIDEBAR DEBUG]', ...args);
   454→      }
   455→    }
   456→
   457→    // Global error handlers
   458→    window.addEventListener('error', (e) => {
   459→      console.error('[SIDEBAR ERROR]', e.error || e.message);
   460→      debug('Error details:', {
   461→        message: e.message,
   462→        filename: e.filename,
   463→        lineno: e.lineno,
   464→        colno: e.colno,
   465→        stack: e.error?.stack
   466→      });
   467→    });
   468→
   469→    window.addEventListener('unhandledrejection', (e) => {
   470→      console.error('[SIDEBAR UNHANDLED REJECTION]', e.reason);
   471→      debug('Promise rejection:', e.reason);
   472→    });
   473→
   474→    let workItems = [];
   475→    let epics = [];
   476→    let expandedItemId = null;
   477→    let expandedItemType = null; // 'epic' or 'workitem'
   478→
   479→    debug('Sidebar script loaded');
   480→    debug('window.api available:', !!window.api);
   481→    debug('Location:', window.location.href);
   482→
   483→    // Listen for data updates
   484→    if (window.api?.sidebar?.onDataUpdate) {
   485→      debug('Registering onDataUpdate listener');
   486→      window.api.sidebar.onDataUpdate((data) => {
   487→        debug('Data update received:', {
   488→          workItems: data.workItems?.length,
   489→          epics: data.epics?.length
   490→        });
   491→        workItems = data.workItems || [];
   492→        epics = data.epics || [];
   493→        render();
   494→      });
   495→    } else {
   496→      debug('WARNING: window.api.sidebar.onDataUpdate not available');
   497→    }
   498→
   499→    // Initial data load
   500→    async function loadInitialData() {
   501→      debug('loadInitialData called');
   502→      if (window.api?.workitems?.load && window.api?.epics?.load) {
   503→        try {
   504→          debug('Loading initial data from IPC...');
   505→          const [wi, ep] = await Promise.all([
   506→            window.api.workitems.load(),
   507→            window.api.epics.load()
   508→          ]);
   509→          debug('Initial data loaded:', {
   510→            workItems: wi?.length,
   511→            epics: ep?.length
   512→          });
   513→          workItems = wi || [];
   514→          epics = ep || [];
   515→          render();
   516→        } catch (error) {
   517→          console.error('[SIDEBAR ERROR] Failed to load:', error);
   518→          debug('Load error details:', error.stack);
   519→        }
   520→      } else {
   521→        debug('WARNING: IPC load methods not available');
   522→      }
   523→    }
   524→
   525→    function render() {
   526→      debug('render() called', {
   527→        totalWorkItems: workItems.length,
   528→        totalEpics: epics.length,
   529→        expandedItemId,
   530→        expandedItemType
   531→      });
   532→
   533→      const loading = document.getElementById('loading');
   534→      const empty = document.getElementById('empty');
   535→      const stats = document.getElementById('stats');
   536→      const epicsSection = document.getElementById('epicsSection');
   537→      const workItemsSection = document.getElementById('workItemsSection');
   538→      const footer = document.getElementById('footer');
   539→
   540→      // Update debug panel
   541→      if (DEBUG) {
   542→        const debugPanel = document.getElementById('debugPanel');
   543→        const debugInfo = document.getElementById('debugInfo');
   544→        debugPanel.style.display = 'block';
   545→        debugInfo.innerHTML = `
   546→          <strong>State:</strong><br>
   547→          • Work Items: ${workItems.length}<br>
   548→          • Epics: ${epics.length}<br>
   549→          • Expanded: ${expandedItemId || 'none'} (${expandedItemType || 'none'})<br>
   550→          • window.api: ${!!window.api ? '✓' : '✗'}<br>
   551→          • Time: ${new Date().toLocaleTimeString()}
   552→        `;
   553→      }
   554→
   555→      loading.style.display = 'none';
   556→
   557→      // Filter open items only (Active, Proposed, New)
   558→      const openEpics = epics.filter(e =>
   559→        ['Active', 'Proposed', 'New'].includes(e.status)
   560→      );
   561→      const openItems = workItems.filter(wi =>
   562→        ['Active', 'Proposed', 'New'].includes(wi.status)
   563→      );
   564→
   565→      debug('Filtered open items:', {
   566→        openEpics: openEpics.length,
   567→        openItems: openItems.length
   568→      });
   569→
   570→      if (openEpics.length === 0 && openItems.length === 0) {
   571→        empty.style.display = 'block';
   572→        stats.style.display = 'none';
   573→        epicsSection.style.display = 'none';
   574→        workItemsSection.style.display = 'none';
   575→        footer.style.display = 'none';
   576→        return;
   577→      }
   578→
   579→      empty.style.display = 'none';
   580→      stats.style.display = 'flex';
   581→      footer.style.display = 'block';
   582→
   583→      // Update stats
   584→      document.getElementById('epicCount').textContent = openEpics.length;
   585→      document.getElementById('activeCount').textContent = openItems.length;
   586→      document.getElementById('totalCount').textContent = openEpics.length + openItems.length;
   587→
   588→      // Render epics table
   589→      if (openEpics.length > 0) {
   590→        epicsSection.style.display = 'block';
   591→        const epicsList = document.getElementById('epicsList');
   592→
   593→        const html = openEpics.map((e, idx) => {
   594→          const itemId = e.id || `NEW-${idx}`;
   595→          const isExpanded = expandedItemType === 'epic' && expandedItemId === itemId;
   596→
   597→          debug(`Rendering epic row ${idx}:`, {
   598→            itemId: JSON.stringify(itemId),
   599→            expandedItemId: JSON.stringify(expandedItemId),
   600→            expandedItemType: JSON.stringify(expandedItemType),
   601→            typeMatch: expandedItemType === 'epic',
   602→            idMatch: expandedItemId === itemId,
   603→            isExpanded: isExpanded
   604→          });
   605→
   606→          return `
   607→            <tr class="item-row ${isExpanded ? 'selected' : ''}" data-id="${itemId}" data-type="epic" title="Click to view details">
   608→              <td class="id">${e.id || 'NEW'}</td>
   609→              <td class="title">${esc(truncate(e.title, 50))}</td>
   610→              <td><span class="badge ${e.status?.toLowerCase()}">${e.status || 'New'}</span></td>
   611→            </tr>
   612→            <tr class="details-row epic-details ${isExpanded ? 'visible' : ''}" data-id="${itemId}">
   613→              <td colspan="3">
   614→                ${renderDetails(e, 'epic', itemId)}
   615→              </td>
   616→            </tr>
   617→          `;
   618→        }).join('');
   619→
   620→        epicsList.innerHTML = html;
   621→        debug('Epics HTML length:', html.length);
   622→        debug('Details rows in DOM:', document.querySelectorAll('.details-row').length);
   623→        debug('Visible details rows:', document.querySelectorAll('.details-row.visible').length);
   624→
   625→        attachRowClickHandlers();
   626→      } else {
   627→        epicsSection.style.display = 'none';
   628→      }
   629→
   630→      // Render work items table
   631→      if (openItems.length > 0) {
   632→        workItemsSection.style.display = 'block';
   633→        const workItemsList = document.getElementById('workItemsList');
   634→
   635→        const html = openItems.map((wi, idx) => {
   636→          const itemId = wi.id || `NEW-${idx}`;
   637→          const isExpanded = expandedItemType === 'workitem' && expandedItemId === itemId;
   638→
   639→          debug(`Rendering work item row ${idx}:`, {
   640→            itemId: JSON.stringify(itemId),
   641→            expandedItemId: JSON.stringify(expandedItemId),
   642→            expandedItemType: JSON.stringify(expandedItemType),
   643→            typeMatch: expandedItemType === 'workitem',
   644→            idMatch: expandedItemId === itemId,
   645→            isExpanded: isExpanded
   646→          });
   647→
   648→          return `
   649→            <tr class="item-row ${isExpanded ? 'selected' : ''}" data-id="${itemId}" data-type="workitem" title="Click to view details">
   650→              <td class="id">${wi.id || 'NEW'}</td>
   651→              <td class="title">${esc(truncate(wi.title, 50))}</td>
   652→              <td><span class="badge ${wi.status?.toLowerCase()}">${wi.status || 'New'}</span></td>
   653→              <td class="priority p${wi.priority || '4'}">${wi.priority || '-'}</td>
   654→            </tr>
   655→            <tr class="details-row ${isExpanded ? 'visible' : ''}" data-id="${itemId}">
   656→              <td colspan="4">
   657→                ${renderDetails(wi, 'workitem', itemId)}
   658→              </td>
   659→            </tr>
   660→          `;
   661→        }).join('');
   662→
   663→        workItemsList.innerHTML = html;
   664→        debug('Work items HTML length:', html.length);
   665→        debug('Details rows in DOM (after work items):', document.querySelectorAll('.details-row').length);
   666→        debug('Visible details rows (after work items):', document.querySelectorAll('.details-row.visible').length);
   667→
   668→        attachRowClickHandlers();
   669→      } else {
   670→        workItemsSection.style.display = 'none';
   671→      }
   672→
   673→      // Update footer
   674→      document.getElementById('syncTime').textContent = new Date().toLocaleTimeString('en-US', {
   675→        hour: '2-digit',
   676→        minute: '2-digit',
   677→        second: '2-digit'
   678→      });
   679→    }
   680→
   681→    function esc(text) {
   682→      const div = document.createElement('div');
   683→      div.textContent = text || '';
   684→      return div.innerHTML;
   685→    }
   686→
   687→    function truncate(text, len) {
   688→      if (!text) return '';
   689→      return text.length > len ? text.substring(0, len) + '...' : text;
   690→    }
   691→
   692→    function renderDetails(item, type, itemId) {
   693→      debug('renderDetails called:', { type, itemId, hasItem: !!item });
   694→      return `
   695→        <div class="details-content">
   696→          <div class="details-header">
   697→            <div class="details-title">${esc(item.title)}</div>
   698→            <div class="details-actions">
   699→              <button class="btn-small popup" onclick="openInPopup('${itemId}', '${type}')">
   700→                Open ⬈
   701→              </button>
   702→              <button class="btn-small" onclick="toggleDetails('${itemId}', '${type}')">
   703→                Close
   704→              </button>
   705→            </div>
   706→          </div>
   707→
   708→          <div class="detail-field">
   709→            <div class="detail-label">ID</div>
   710→            <div class="detail-value">${item.id || 'Not yet created'}</div>
   711→          </div>
   712→
   713→          ${item.description ? `
   714→            <div class="detail-field">
   715→              <div class="detail-label">Description</div>
   716→              <div class="detail-value">${esc(item.description)}</div>
   717→            </div>
   718→          ` : ''}
   719→
   720→          <div class="detail-field">
   721→            <div class="detail-label">Status</div>
   722→            <div class="detail-value">
   723→              <span class="badge ${item.status?.toLowerCase()}">${item.status || 'New'}</span>
   724→            </div>
   725→          </div>
   726→
   727→          ${type === 'workitem' ? `
   728→            <div class="detail-field">
   729→              <div class="detail-label">Priority</div>
   730→              <div class="detail-value priority p${item.priority || '4'}">P${item.priority || '4'}</div>
   731→            </div>
   732→          ` : ''}
   733→
   734→          ${item.assignedTo ? `
   735→            <div class="detail-field">
   736→              <div class="detail-label">Assigned To</div>
   737→              <div class="detail-value">${esc(item.assignedTo)}</div>
   738→            </div>
   739→          ` : ''}
   740→
   741→          ${item.areaPath ? `
   742→            <div class="detail-field">
   743→              <div class="detail-label">Area Path</div>
   744→              <div class="detail-value">${esc(item.areaPath)}</div>
   745→            </div>
   746→          ` : ''}
   747→
   748→          ${item.iterationPath ? `
   749→            <div class="detail-field">
   750→              <div class="detail-label">Iteration</div>
   751→              <div class="detail-value">${esc(item.iterationPath)}</div>
   752→            </div>
   753→          ` : ''}
   754→
   755→          ${item.tags && item.tags.length > 0 ? `
   756→            <div class="detail-field">
   757→              <div class="detail-label">Tags</div>
   758→              <div class="detail-value">${item.tags.map(t => esc(t)).join(', ')}</div>
   759→            </div>
   760→          ` : ''}
   761→
   762→          ${item.createdDate ? `
   763→            <div class="detail-field">
   764→              <div class="detail-label">Created</div>
   765→              <div class="detail-value">${new Date(item.createdDate).toLocaleString()}</div>
   766→            </div>
   767→          ` : ''}
   768→
   769→          ${item.changedDate ? `
   770→            <div class="detail-field">
   771→              <div class="detail-label">Last Updated</div>
   772→              <div class="detail-value">${new Date(item.changedDate).toLocaleString()}</div>
   773→            </div>
   774→          ` : ''}
   775→        </div>
   776→      `;
   777→    }
   778→
   779→    function toggleDetails(itemId, type) {
   780→      debug('toggleDetails called:', { itemId, type, currentExpanded: expandedItemId });
   781→
   782→      if (expandedItemId === itemId && expandedItemType === type) {
   783→        // Collapse if already expanded
